const categoryForMapping=(m:Pick<Mapping,'targetKind'|'property'>):VisualCategory=>m.targetKind==='field'||m.targetKind==='path'?'constraint':m.targetKind==='group'?'composition':['color','opacity'].includes(m.property)?'appearance':'geometry';
const mappingGradient=(source:SourceId,category:VisualCategory)=>`linear-gradient(90deg, ${sourceMeta[source].color}, ${visualMeta[category].color})`;
const mappingPropertyLabel=(m:Pick<Mapping,'targetKind'|'property'>)=>m.targetKind==='members'&&propertyLabels[m.property]&&!propertyLabels[m.property].startsWith('成员')?`成员 ${propertyLabels[m.property]}`:propertyLabels[m.property]||m.property;
