  const [mappingFocus,setMappingFocus]=useState(false);
  const [hoveredSource,setHoveredSource]=useState<{id:SourceId;track?:string}>();
  const [rotationCursor,setRotationCursor]=useState<{x:number;y:number}|null>(null);
  const [renaming,setRenaming]=useState<{kind:'shape'|'group';id:string}|null>(null);const [renameDraft,setRenameDraft]=useState('');
  const [tick,setTick]=useState(0); const [activeMap,setActiveMap]=useState<string>(); const [dragSource,setDragSource]=useState<SourceId>(); const [dragSourceTrack,setDragSourceTrack]=useState<string>();
