    const pannedEvents=(runtimeMidi?.events||[]).filter(event=>event.pan!==undefined).sort((a,b)=>a.start-b.start),currentPannedEvent=pannedEvents.filter(event=>event.start<=runtimeMidi!.end&&event.end>=runtimeMidi!.end-Math.max(.03,(runtimeMidi!.end-runtimeMidi!.begin)/80)).at(-1),pan=currentPannedEvent?.pan??pannedEvents.at(-1)?.pan??0;
