function Inspector({state,selectedShapes,group,field,mappings,patchShape,patchGroupMembers,groupSelection,ungroup,patchGroup,setCount,addPath,addField,patchField,onDrop,setActiveMap}:{state:AppState;selectedShapes:Shape[];group?:Group;field?:Field;mappings:Mapping[];patchShape:(id:string,p:Partial<Shape>)=>void;patchGroupMembers:(p:Partial<Shape>)=>void;groupSelection:()=>void;ungroup:()=>void;patchGroup:(p:Partial<Group>)=>void;setCount:(n:number)=>void;addPath:()=>void;addField:()=>void;patchField:(p:Partial<Field>)=>void;onDrop:(k:Mapping['targetKind'],id:string,p:string,b:number)=>(e:React.DragEvent)=>void;setActiveMap:(id:string)=>void}){
  if(selectedShapes.length>1)return <><PanelTitle icon={<Settings2 size={15}/>} title="多选属性"/><div className="selection-summary"><div className="multi-icons">{selectedShapes.slice(0,4).map((s,i)=><span key={s.id} style={{background:s.fill,transform:`translateX(${-i*6}px)`}}/> )}</div><b>已选择 {selectedShapes.length} 个元素</b><small>将元素组合后可设置构成、成员顺序与序列映射。</small><button className="primary wide" onClick={groupSelection}><GroupIcon size={15}/> 建立元素组</button></div><InfoBlock/></>;
  if(group){const members=group.memberIds.map(id=>state.shapes.find(s=>s.id===id)).filter(Boolean) as Shape[],proto=members[0];return <><div className="group-inspector-summary"><div className="group-summary-icon"><GroupIcon size={18}/></div><div><b>{group.name}</b><small>{members.length} 个成员 · {compLabels[group.composition]} · 非嵌套组</small></div><button title="解组" onClick={ungroup}><Ungroup size={17}/></button><button title={group.hidden?'显示组':'隐藏组'} onClick={()=>patchGroup({hidden:!group.hidden})}>{group.hidden?<EyeOff size={17}/>:<Eye size={17}/>}</button></div>
    {proto&&<Fold title="成员变换与外观" badge="拖入声音参数可映射"><div className="two-col"><DropProperty label="成员宽度 / X 缩放" value={proto.width} bound={findMap(mappings,group.id,'scaleX')} onDrop={onDrop('members',group.id,'scaleX',1)} setActiveMap={setActiveMap} onChange={v=>patchGroupMembers({width:v})}/><DropProperty label="成员高度 / Y 缩放" value={proto.height} bound={findMap(mappings,group.id,'scaleY')} onDrop={onDrop('members',group.id,'scaleY',1)} setActiveMap={setActiveMap} onChange={v=>patchGroupMembers({height:v})}/><DropProperty label="成员旋转" value={proto.rotation} bound={findMap(mappings,group.id,'rotation')} onDrop={onDrop('members',group.id,'rotation',proto.rotation)} setActiveMap={setActiveMap} onChange={v=>patchGroupMembers({rotation:v})}/><DropProperty label="成员透明度" value={proto.opacity} bound={findMap(mappings,group.id,'opacity')} onDrop={onDrop('members',group.id,'opacity',proto.opacity)} setActiveMap={setActiveMap} onChange={v=>patchGroupMembers({opacity:v})}/></div><label className={`color-row member-color ${findMap(mappings,group.id,'color')?'bound':''}`} onDragOver={e=>e.preventDefault()} onDrop={onDrop('members',group.id,'color',0)}><span>成员颜色</span><input type="color" value={proto.fill} onChange={e=>patchGroupMembers({fill:e.target.value})}/><code>{proto.fill.toUpperCase()}</code>{findMap(mappings,group.id,'color')&&<Link2 size={11}/>}</label><div className="member-map-note"><Waves size={13}/><span>频谱序列会按 {members.length} 个成员自动重采样并按稳定顺序应用</span></div></Fold>}
    <Fold title="构成关系" badge={compLabels[group.composition]}><div className="comp-grid">{compositionOptions.map(c=><button key={c} className={group.composition===c?'active':''} onClick={()=>patchGroup({composition:c})}>{c==='horizontal'?'↔':c==='vertical'?'↕':c==='grid'?'▦':c==='radial'?'◌':'⌁'}<span>{compLabels[c]}</span></button>)}</div><div className="two-col"><Property label="数量" value={group.count} onChange={v=>setCount(Math.max(1,Math.round(v)))}/>{group.composition==='radial'||group.composition==='random'?<Property label="范围 / 半径" value={group.radius} onChange={v=>patchGroup({radius:v})}/>:<Property label="间距" value={group.spacing} onChange={v=>patchGroup({spacing:v})}/>}<Property label="排列偏移" value={group.offset} onChange={v=>patchGroup({offset:v})}/></div><label className="toggle-row"><span><b>透视</b><small>播放区域中心为透视点 · 中心小、边缘大</small></span><input type="checkbox" checked={group.perspective} onChange={e=>patchGroup({perspective:e.target.checked})}/></label>{group.perspective&&<Property label="透视强度" value={group.perspectiveStrength} step={.05} onChange={v=>patchGroup({perspectiveStrength:v})}/>}<label className="toggle-row compact"><span>成员顺序反向</span><input type="checkbox" checked={group.reverse} onChange={e=>patchGroup({reverse:e.target.checked})}/></label></Fold>
    <Fold title="空间路径" badge={group.path?'已绑定':'未绑定'}><button className="outline wide" onClick={addPath}><Route size={15}/>{group.path?'编辑贝塞尔路径':'为元素组建立路径'}</button>{group.path&&<><div className="segmented">{(['line','circle','bezier','free'] as const).map(k=><button className={group.path?.kind===k?'active':''} onClick={()=>patchGroup({path:{...group.path!,kind:k}})} key={k}>{k==='line'?'直线':k==='circle'?'圆':'bezier'===k?'贝塞尔':'自由'}</button>)}</div><div className="two-col"><DropProperty label="偏离距离" value={group.path.offset} bound={findMap(mappings,group.id,'offset')} onDrop={onDrop('path',group.id,'offset',group.path.offset)} setActiveMap={setActiveMap}/><DropProperty label="朝向偏移" value={group.path.angleOffset} bound={findMap(mappings,group.id,'angleOffset')} onDrop={onDrop('path',group.id,'angleOffset',group.path.angleOffset)} setActiveMap={setActiveMap}/></div></>}</Fold><Fold title="附属辅助层" badge={`${state.fields.filter(f=>f.ownerId===group.id).length}`}><button className="outline wide" onClick={addField}><Plus size={14}/> 添加移动影响层</button></Fold></>}
  if(field)return <><PanelTitle icon={<Move size={15}/>} title="移动影响层"/><InspectorHeader title={field.name} type="二维移动向量场" color="#ff8a42"/><Fold title="力场属性" badge="累加"><div className="segmented">{([['directional','固定方向'],['attract','向心吸引'],['repel','中心排斥']] as [FieldKind,string][]).map(([k,l])=><button key={k} className={field.kind===k?'active':''} onClick={()=>patchField({kind:k})}>{l}</button>)}</div><div className="two-col"><DropProperty label="中心 X" value={field.x} bound={findMap(mappings,field.id,'x')} onDrop={onDrop('field',field.id,'x',field.x)} setActiveMap={setActiveMap}/><DropProperty label="中心 Y" value={field.y} bound={findMap(mappings,field.id,'y')} onDrop={onDrop('field',field.id,'y',field.y)} setActiveMap={setActiveMap}/><DropProperty label="范围" value={field.radius} bound={findMap(mappings,field.id,'radius')} onDrop={onDrop('field',field.id,'radius',field.radius)} setActiveMap={setActiveMap}/><DropProperty label="强度" value={field.strength} bound={findMap(mappings,field.id,'strength')} onDrop={onDrop('field',field.id,'strength',field.strength)} setActiveMap={setActiveMap}/><DropProperty label="方向" value={field.direction} bound={findMap(mappings,field.id,'direction')} onDrop={onDrop('field',field.id,'direction',field.direction)} setActiveMap={setActiveMap}/></div><label className="select-label">衰减<select value={field.falloff} onChange={e=>patchField({falloff:e.target.value as Field['falloff']})}><option value="uniform">均匀</option><option value="radial">中心强 · 边缘弱</option></select></label></Fold><div className="calc-order"><Zap size={15}/><div><b>固定计算顺序</b><small>声音映射 → 基础结果 → 路径 → 移动影响累加</small></div></div></>;
  if(selectedShapes.length===1){const s=selectedShapes[0];return <><InspectorHeader title={s.name} type={s.kind==='circle'?'圆形':s.kind==='rect'?'矩形':'直线'} color={s.fill} actions={<><button title="建立元素组" onClick={groupSelection}><GroupIcon size={16}/></button><button title={s.hidden?'显示元素':'隐藏元素'} onClick={()=>patchShape(s.id,{hidden:!s.hidden})}>{s.hidden?<EyeOff size={16}/>:<Eye size={16}/>}</button></>}/><Fold title="变换" badge="可映射"><div className="two-col"><DropProperty label="X" value={s.x} bound={findMap(mappings,s.id,'x')} onDrop={onDrop('shape',s.id,'x',s.x)} setActiveMap={setActiveMap} onChange={v=>patchShape(s.id,{x:v})}/><DropProperty label="Y" value={s.y} bound={findMap(mappings,s.id,'y')} onDrop={onDrop('shape',s.id,'y',s.y)} setActiveMap={setActiveMap} onChange={v=>patchShape(s.id,{y:v})}/><DropProperty label="宽度" value={s.width} bound={findMap(mappings,s.id,'width')} onDrop={onDrop('shape',s.id,'width',s.width)} setActiveMap={setActiveMap} onChange={v=>patchShape(s.id,{width:v})}/><DropProperty label="高度 / 缩放" value={s.height} bound={findMap(mappings,s.id,'scale')} onDrop={onDrop('shape',s.id,'scale',1)} setActiveMap={setActiveMap} onChange={v=>patchShape(s.id,{height:v})}/><DropProperty label="旋转" value={s.rotation} bound={findMap(mappings,s.id,'rotation')} onDrop={onDrop('shape',s.id,'rotation',s.rotation)} setActiveMap={setActiveMap} onChange={v=>patchShape(s.id,{rotation:v})}/><DropProperty label="透明度" value={s.opacity} bound={findMap(mappings,s.id,'opacity')} onDrop={onDrop('shape',s.id,'opacity',s.opacity)} setActiveMap={setActiveMap} onChange={v=>patchShape(s.id,{opacity:v})}/></div></Fold><Fold title="外观" badge={findMap(mappings,s.id,'color')?'已绑定':'基础'}><label className="color-row"><span>颜色</span><input type="color" value={s.fill} onChange={e=>patchShape(s.id,{fill:e.target.value})}/><code>{s.fill.toUpperCase()}</code></label></Fold><Fold title="空间路径" badge="未绑定"><button className="outline wide"><Route size={15}/> 为元素建立路径</button></Fold><Fold title="附属辅助层" badge={`${state.fields.filter(f=>f.ownerId===s.id).length}`}><button className="outline wide" onClick={addField}><Plus size={14}/> 添加移动影响层</button></Fold></>}
  return <><PanelTitle icon={<Settings2 size={15}/>} title="属性"/><div className="nothing-selected"><SquareDashedMousePointer size={32}/><b>选择画布中的对象</b><span>单击元素查看属性<br/>Shift 单击可多选并成组</span></div><InfoBlock/></>;
}
function findMap(ms:Mapping[],id:string,p:string){return ms.find(m=>m.targetId===id&&m.property===p)}
function InspectorHeader({title,type,color,actions}:{title:string;type:string;color:string;actions?:React.ReactNode}){return <div className="inspector-header"><i style={{background:color}}/><div><b>{title}</b><small>{type}</small></div><div className="inspector-header-actions">{actions||<button><Eye size={15}/></button>}</div></div>}
function Fold({title,badge,children}:{title:string;badge?:string;children:React.ReactNode}){return <section className="fold"><div className="fold-head"><ChevronDown size={14}/><b>{title}</b>{badge&&<span>{badge}</span>}</div><div className="fold-body">{children}</div></section>}
function Property({label,value,onChange,step=1}:{label:string;value:number;onChange?:(n:number)=>void;step?:number}){return <label className="property"><span>{label}</span><input type="number" value={Number(value.toFixed(2))} step={step} onChange={e=>onChange?.(+e.target.value)}/></label>}
function DropProperty({label,value,bound,onDrop,setActiveMap,onChange}:{label:string;value:number;bound?:Mapping;onDrop:(e:React.DragEvent)=>void;setActiveMap:(id:string)=>void;onChange?:(n:number)=>void}){return <label className={`property drop-property ${bound?'bound':''}`} onDragOver={e=>e.preventDefault()} onDrop={onDrop} onClick={()=>bound&&setActiveMap(bound.id)}><span>{label}{bound&&<Link2 size={10}/>}</span><input type="number" value={Number(value.toFixed(2))} readOnly={!!bound} onChange={e=>onChange?.(+e.target.value)}/>{bound&&<i style={{background:sourceMeta[bound.source].color}}/>}</label>}
function InfoBlock(){return <div className="help-card"><Sparkles size={15}/><div><b>编辑提示</b><small>双指平移 · 捏合缩放 · 空格拖动画布<br/>V/O/R/L 切换工具 · ⌘Z 撤销</small></div></div>}
function mappingTargetName(m:Mapping,state:AppState){const base=state.shapes.find(s=>s.id===m.targetId)?.name||state.groups.find(g=>g.id===m.targetId)?.name||state.fields.find(f=>f.id===m.targetId)?.name||'空间路径';return m.targetKind==='members'?`${base} · 组内成员`:base}
function MappingIndexRow({m,active,state,onClick,toggle,remove}:{m:Mapping;active:boolean;state:AppState;onClick:()=>void;toggle:()=>void;remove:()=>void}){const category=categoryForMapping(m);return <div className={`mapping-index-row ${active?'active':''} ${!m.enabled?'disabled':''}`} onClick={onClick}><i style={{background:mappingGradient(m.source,category)}}/><div><b>{sourceDisplayLabel(m.source,m.sourceTrack)} <span>→</span> {mappingPropertyLabel(m)}</b><small>{mappingTargetName(m,state)} · {visualMeta[category].label}</small></div><button title={m.enabled?'暂停映射':'启用映射'} aria-label={m.enabled?'暂停映射':'启用映射'} onClick={e=>{e.stopPropagation();toggle()}}>{m.enabled?<Eye size={12}/>:<EyeOff size={12}/>}</button><button className="mapping-index-delete" title="删除映射" aria-label="删除映射" onClick={e=>{e.stopPropagation();remove()}}><Trash2 size={12}/></button></div>}
function MappingDraftCard(){return null}
function MappingCard(){return null}
function visibleMappingMembers(state:AppState,groupId:string){const group=state.groups.find(g=>g.id===groupId);if(!group)return 0;return group.memberIds.filter((id,index)=>index<group.count&&!state.shapes.find(s=>s.id===id)?.hidden).length}
function sourceValueText(source:SourceId,audio:AudioValues,track?:string){if(isSequenceSource(source))return`${sequenceForSource(source,audio).length} VALUES`;const value=sourceRawValue(source,audio,track);return source==='pitch'?String(Math.round(value)):value.toFixed(2)}
function formatMappedValue(value:number,property:string){if(property==='count')return String(Math.round(value));if(Math.abs(value)>=100)return value.toFixed(0);return value.toFixed(2)}
function useSmoothedPreview(target:number,smooth:boolean){const value=useRef(target);value.current=smooth?value.current+(target-value.current)*.16:target;return value.current}
function SourceSignal({source,audio,track}:{source:SourceId;audio:AudioValues;track?:string}){const level=normalizedInput(source,audio,track);if(isSequenceSource(source))return <span className="source-signal sequence" aria-hidden="true">{sequenceForSource(source,audio).slice(-5).map((v,i)=><i key={i} style={{height:`${5+v*20}px`}}/>)}</span>;if(sourceMeta[source].family==='rhythm')return <span className={`source-signal pulse ${sourceRawValue(source,audio,track)?'on':''}`} aria-hidden="true"><i/></span>;return <span className={`source-signal ${sourceMeta[source].family==='melody'?'melody':'scalar'}`} aria-hidden="true"><i style={{height:`${6+level*22}px`}}/></span>}
function MappingHeaderV2({source,sourceTrack,property,audio,output,back}:{source:SourceId;sourceTrack?:string;property:string;audio:AudioValues;output:string;back?:()=>void}){return <div className="mapping-v2-head">{back&&<button className="mapping-back" onClick={back} aria-label="重新选择属性"><ChevronLeft size={20}/></button>}<div className="mapping-source-live"><SourceSignal source={source} track={sourceTrack} audio={audio}/><div><b>{sourceDisplayLabel(source,sourceTrack)}</b><strong>{sourceValueText(source,audio,sourceTrack)}</strong></div></div><span className="mapping-arrow">→</span><div className="mapping-target-title"><b>{property}</b><strong>{output}</strong></div></div>}
function NumericMappingBody({source,sourceTrack,property,min,max,reverse,colorA,colorB,audio,patch,position:previewPosition}:{source:SourceId;sourceTrack?:string;property:string;min:number;max:number;reverse:boolean;colorA:string;colorB:string;audio:AudioValues;patch:(p:Record<string,unknown>)=>void;position?:number}){let position=previewPosition??normalizedInput(source,audio,sourceTrack);if(previewPosition===undefined&&reverse)position=1-position;const isColor=property==='color',value=min+(max-min)*position,outputColor=mixColor(colorA,colorB,position),trackBackground=isColor?`linear-gradient(90deg,${colorA},${colorB})`:'linear-gradient(90deg,#343d46,#a8ff3e)';return <><div className="mapping-preview-track" style={{background:trackBackground}}><i style={{left:`${position*100}%`}}><span>{isColor?outputColor.toUpperCase():formatMappedValue(value,property)}</span></i></div><div className={`absolute-range-inputs ${isColor?'color-range':''}`}>{isColor?<><label><input type="color" value={colorA} onChange={e=>patch({colorA:e.target.value})}/><span>起始颜色</span></label><label><input type="color" value={colorB} onChange={e=>patch({colorB:e.target.value})}/><span>结束颜色</span></label></>:<><label><input type="number" value={Number(min.toFixed(2))} step=".1" onChange={e=>patch({min:+e.target.value})}/><span>目标最小值</span></label><label><input type="number" value={Number(max.toFixed(2))} step=".1" onChange={e=>patch({max:+e.target.value})}/><span>目标最大值</span></label></>}</div></>}
function SequenceMappingBody({source,property,min,max,reverse,sampling,colorA,colorB,audio,state,groupId,patch}:{source:SourceId;property:string;min:number;max:number;reverse:boolean;sampling:Mapping['sampling'];colorA:string;colorB:string;audio:AudioValues;state:AppState;groupId:string;patch:(p:Record<string,unknown>)=>void}){const sequence=sequenceForSource(source,audio),count=visibleMappingMembers(state,groupId),sampled=sampleSequence(sequence,count,sampling),ordered=reverse?[...sampled].reverse():sampled,outputs=ordered.map(v=>min+(max-min)*v),isColor=property==='color';return <div className="sequence-editor-v2"><div className="sequence-flow"><section><header><b>原始序列</b><span>{sequence.length} 项</span></header><div className="mini-spectrum raw">{sequence.map((v,i)=><i key={i} style={{height:`${5+v*34}px`}}/>)}</div></section><span>↓</span><section><header><b>成员输出</b><span>{count} 可见成员 · {ordered.length} 项</span></header><div className="mini-spectrum sampled">{ordered.map((v,i)=><i key={i} style={{height:`${6+v*34}px`,background:isColor?mixColor(colorA,colorB,v):undefined}} title={isColor?mixColor(colorA,colorB,v):formatMappedValue(outputs[i],property)}/>)}</div></section></div><div className="sequence-settings"><label><span>采样方式</span><select value={sampling} onChange={e=>patch({sampling:e.target.value})}><option value="average">平均采样</option><option value="peak">峰值采样</option><option value="linear">线性插值</option></select></label><div><span>输出数量</span><strong>{ordered.length}</strong><small>= 可见成员数</small></div></div><div className={`absolute-range-inputs ${isColor?'color-range':''}`}>{isColor?<><label><input type="color" value={colorA} onChange={e=>patch({colorA:e.target.value})}/><span>起始颜色</span></label><label><input type="color" value={colorB} onChange={e=>patch({colorB:e.target.value})}/><span>结束颜色</span></label></>:<><label><input type="number" value={Number(min.toFixed(2))} step=".1" onChange={e=>patch({min:+e.target.value})}/><span>目标最小值</span></label><label><input type="number" value={Number(max.toFixed(2))} step=".1" onChange={e=>patch({max:+e.target.value})}/><span>目标最大值</span></label></>}</div></div>}
function MappingDraftCardV2({draft,options,state,audio,style,choose,patch,confirm,replace,reselect,cancel}:{draft:MappingDraft;options:MappingOption[];state:AppState;audio:AudioValues;style:React.CSSProperties;choose:(o:MappingOption)=>void;patch:(p:Partial<MappingDraft>)=>void;confirm:()=>void;replace:()=>void;reselect:()=>void;cancel:()=>void}){
  const sections=[...new Set(options.map(o=>o.section))],option=draft.option,label=sourceDisplayLabel(draft.source,draft.sourceTrack);let rawPosition=normalizedInput(draft.source,audio,draft.sourceTrack);if(draft.reverse&&!isSequenceSource(draft.source))rawPosition=1-rawPosition;const previewPosition=useSmoothedPreview(rawPosition,draft.smooth&&!isSequenceSource(draft.source));
  if(!option)return <div className="mapping-draft-card mapping-v2" style={style}><div className="draft-head"><i style={{background:sourceMeta[draft.source].color}}/><div><div className="draft-head-title"><b>{label} → 选择视觉属性</b><span>选择这个声音参数要驱动的属性</span></div><small>{draft.targetName}</small></div><button onClick={cancel}><X size={14}/></button></div><div className="draft-property-picker">{sections.map(section=><section key={section}><label>{section}</label><div>{options.filter(o=>o.section===section).map(o=><button key={`${o.targetKind}-${o.targetId}-${o.property}`} onClick={()=>choose(o)}><i style={{background:visualMeta[o.category].color}}/>{o.label}<ChevronRight size={12}/></button>)}</div></section>)}</div></div>;
  if(draft.conflictId)return <div className="mapping-draft-card mapping-v2" style={style}><div className="mapping-conflict"><AlertTriangle size={20}/><b>该属性已有映射</b><span>同一属性只能保留一条映射关系。</span><div><button className="danger" onClick={replace}>替换原映射</button><button onClick={reselect}>重新选择</button><button onClick={cancel}>取消</button></div></div></div>;
  const output=isSequenceSource(draft.source)?(()=>{const values=sampleSequence(sequenceForSource(draft.source,audio),visibleMappingMembers(state,option.targetId),draft.sampling).map(v=>draft.min+(draft.max-draft.min)*v);return values.length?`${formatMappedValue(Math.min(...values),option.property)}—${formatMappedValue(Math.max(...values),option.property)}`:'0 项'})():option.property==='color'?mixColor(draft.colorA,draft.colorB,previewPosition).toUpperCase():formatMappedValue(draft.min+(draft.max-draft.min)*previewPosition,option.property);
  return <div className="mapping-draft-card mapping-v2" style={style}><MappingHeaderV2 source={draft.source} sourceTrack={draft.sourceTrack} property={option.label} audio={audio} output={output} back={reselect}/><div className="mapping-v2-body">{isSequenceSource(draft.source)?<SequenceMappingBody source={draft.source} property={option.property} min={draft.min} max={draft.max} reverse={draft.reverse} sampling={draft.sampling} colorA={draft.colorA} colorB={draft.colorB} audio={audio} state={state} groupId={option.targetId} patch={p=>patch(p as Partial<MappingDraft>)}/>:<NumericMappingBody source={draft.source} sourceTrack={draft.sourceTrack} property={option.property} min={draft.min} max={draft.max} reverse={draft.reverse} colorA={draft.colorA} colorB={draft.colorB} audio={audio} position={previewPosition} patch={p=>patch(p as Partial<MappingDraft>)}/>}</div><div className="mapping-v2-actions"><label><input type="checkbox" checked={draft.reverse} onChange={e=>patch({reverse:e.target.checked})}/><span>反向</span></label>{!isSequenceSource(draft.source)&&<label title="让离散声音数据连续过渡"><input type="checkbox" checked={draft.smooth} onChange={e=>patch({smooth:e.target.checked})}/><span>平滑</span></label>}<div><button onClick={cancel}>取消</button><button className="confirm" onClick={confirm}><Check size={15}/>确认</button></div></div></div>
}
function MappingCardV2({m,state,audio,save,close,remove}:{m:Mapping;state:AppState;audio:AudioValues;save:(p:Partial<Mapping>)=>void;close:()=>void;remove:()=>void}){const[edit,setEdit]=useState<Mapping>({...m,colorA:m.colorA||'#775cff',colorB:m.colorB||'#a8ff3e'}),patch=(p:Record<string,unknown>)=>setEdit(value=>({...value,...p}));let position=normalizedInput(edit.source,audio);if(edit.reverse&&!isSequenceSource(edit.source))position=1-position;const sequenceValues=isSequenceSource(edit.source)?sampleSequence(sequenceForSource(edit.source,audio),visibleMappingMembers(state,edit.targetId),edit.sampling).map(v=>edit.min+(edit.max-edit.min)*v):[],output=isSequenceSource(edit.source)?(sequenceValues.length?`${formatMappedValue(Math.min(...sequenceValues),edit.property)}—${formatMappedValue(Math.max(...sequenceValues),edit.property)}`:'0 项'):edit.property==='color'?mixColor(edit.colorA!,edit.colorB!,position).toUpperCase():formatMappedValue(edit.min+(edit.max-edit.min)*position,edit.property);return <div className={`mapping-card mapping-card-v2 ${!m.enabled?'disabled':''}`}><MappingHeaderV2 source={edit.source} property={mappingPropertyLabel(edit)} audio={audio} output={output}/><div className="mapping-v2-body">{isSequenceSource(edit.source)?<SequenceMappingBody source={edit.source} property={edit.property} min={edit.min} max={edit.max} reverse={edit.reverse} sampling={edit.sampling} colorA={edit.colorA!} colorB={edit.colorB!} audio={audio} state={state} groupId={edit.targetId} patch={patch}/>:<NumericMappingBody source={edit.source} property={edit.property} min={edit.min} max={edit.max} reverse={edit.reverse} colorA={edit.colorA!} colorB={edit.colorB!} audio={audio} patch={patch}/>}</div><div className="mapping-v2-actions"><label><input type="checkbox" checked={edit.reverse} onChange={e=>patch({reverse:e.target.checked})}/><span>反向</span></label><button className="mapping-delete" onClick={remove}><Trash2 size={13}/></button><div><button onClick={close}>取消</button><button className="confirm" onClick={()=>{save(edit);close()}}><Check size={15}/>确认</button></div></div></div>}
function MappingCardV3({m,state,audio,patch,remove}:{m:Mapping;state:AppState;audio:AudioValues;patch:(p:Partial<Mapping>)=>void;remove:()=>void}){const colorA=m.colorA||'#775cff',colorB=m.colorB||'#a8ff3e',apply=(p:Record<string,unknown>)=>patch(p as Partial<Mapping>);let target=normalizedInput(m.source,audio,m.sourceTrack);if(m.reverse&&!isSequenceSource(m.source))target=1-target;const position=useSmoothedPreview(target,m.smooth&&!isSequenceSource(m.source)),sequenceValues=isSequenceSource(m.source)?sampleSequence(sequenceForSource(m.source,audio),visibleMappingMembers(state,m.targetId),m.sampling).map(v=>m.min+(m.max-m.min)*v):[],output=isSequenceSource(m.source)?(sequenceValues.length?`${formatMappedValue(Math.min(...sequenceValues),m.property)}—${formatMappedValue(Math.max(...sequenceValues),m.property)}`:'0 项'):m.property==='color'?mixColor(colorA,colorB,position).toUpperCase():formatMappedValue(m.min+(m.max-m.min)*position,m.property);return <div className={`mapping-card mapping-card-v2 ${!m.enabled?'disabled':''}`}><MappingHeaderV2 source={m.source} sourceTrack={m.sourceTrack} property={mappingPropertyLabel(m)} audio={audio} output={output}/><div className="mapping-v2-body">{isSequenceSource(m.source)?<SequenceMappingBody source={m.source} property={m.property} min={m.min} max={m.max} reverse={m.reverse} sampling={m.sampling} colorA={colorA} colorB={colorB} audio={audio} state={state} groupId={m.targetId} patch={apply}/>:<NumericMappingBody source={m.source} sourceTrack={m.sourceTrack} property={m.property} min={m.min} max={m.max} reverse={m.reverse} colorA={colorA} colorB={colorB} audio={audio} position={position} patch={apply}/>}</div><div className="mapping-v2-actions established"><label><input type="checkbox" checked={m.reverse} onChange={e=>patch({reverse:e.target.checked})}/><span>反向</span></label>{!isSequenceSource(m.source)&&<label title="让离散声音数据连续过渡"><input type="checkbox" checked={m.smooth} onChange={e=>patch({smooth:e.target.checked})}/><span>平滑</span></label>}<button className="mapping-delete" onClick={remove}><Trash2 size={14}/><span>删除映射</span></button></div></div>}

export default App;
